mapper.select:
SELECT de_num AS deNum , user_seq AS userSEQ , de_name AS deName , receiver_name AS receiverName , address , address_zip AS addressZip , detail_address AS detailAddress , phone1 , phone2 , dlvrpl FROM Delivery WHERE 1=1
AND user_seq = #{userSeq}
ORDER BY deNum DESC

mapper.insert:
INSERT INTO 
	DELIVERY (
		de_num
		, user_seq
		, de_name
		, receiver_name
		, address
		, address_zip
		, detail_address
		, phone1
		, phone2
		, dlvrpl
				)
VALUES (
	DELIVERY_SEQ.NEXTVAL
	, #{userSeq, jdbcType=VARCHAR}
	, #{deName, jdbcType=VARCHAR}
	, #{receiverName, jdbcType=VARCHAR}
	, #{address, jdbcType=VARCHAR}
	, #{addressZip, jdbcType=VARCHAR}
	, #{detailAddress, jdbcType=VARCHAR}
	, #{phone1, jdbcType=VARCHAR}
	, #{phone2, jdbcType=VARCHAR}
	, #{dlvrpl, jdbcType=VARCHAR}	
	)
